import { useEffect, useState } from "react";
import api from "../api";

export default function Events() {
    const [rows, setRows] = useState([]);
    const [form, setForm] = useState({ date:"", time:"", type:"APPOINTMENT", relatedId:"", note:"", owner:"", status:"OPEN" });
    const [saving, setSaving] = useState(false);
    const [loading, setLoading] = useState(true);

    const load = async () => {
        setLoading(true);
        try {
            const { data } = await api.get("/api/events");
            setRows(data||[]);
        } finally { setLoading(false); }
    };
    useEffect(()=>{ load(); },[]);

    const save = async (e) => {
        e.preventDefault();
        setSaving(true);
        try {
            await api.post("/api/events", {
                date: form.date, time: form.time, type: form.type, related: form.relatedId, note: form.note, owner: form.owner, status: form.status
            });
            setForm(s=>({...s, date:"", time:"", note:"", owner:""}));
            await load();
        } finally { setSaving(false); }
    };

    return (
        <div className="space-y-4">
            <h2 className="text-lg font-semibold">Sự kiện & Nhắc nhở</h2>

            <form onSubmit={save} className="bg-white rounded-2xl border border-indigo-100 shadow p-4 grid grid-cols-1 md:grid-cols-6 gap-3">
                <input type="date" className="px-3 py-2 rounded-lg border" value={form.date} onChange={e=>setForm(s=>({...s,date:e.target.value}))}/>
                <input type="time" className="px-3 py-2 rounded-lg border" value={form.time} onChange={e=>setForm(s=>({...s,time:e.target.value}))}/>
                <select className="px-3 py-2 rounded-lg border" value={form.type} onChange={e=>setForm(s=>({...s,type:e.target.value}))}>
                    <option value="APPOINTMENT">Lịch hẹn</option>
                    <option value="REMIND_PAYMENT">Nhắc thanh toán</option>
                    <option value="RENEW_CONTRACT">Gia hạn hợp đồng</option>
                </select>
                <input className="px-3 py-2 rounded-lg border" placeholder="Liên quan (ID KH/HĐ)" value={form.relatedId} onChange={e=>setForm(s=>({...s,relatedId:e.target.value}))}/>
                <input className="px-3 py-2 rounded-lg border" placeholder="Người phụ trách" value={form.owner} onChange={e=>setForm(s=>({...s,owner:e.target.value}))}/>
                <button disabled={saving} className="px-3 py-2 rounded-lg bg-indigo-600 text-white">{saving?"Đang lưu...":"Tạo"}</button>
            </form>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full">
                        <thead className="bg-indigo-50">
                        <tr className="text-left text-slate-600">
                            <th className="px-4 py-3">Ngày/Giờ</th>
                            <th className="px-4 py-3">Loại</th>
                            <th className="px-4 py-3">Liên quan</th>
                            <th className="px-4 py-3">Người phụ trách</th>
                            <th className="px-4 py-3">Trạng thái</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {!loading && rows.map(e=>(
                            <tr key={e.id} className="hover:bg-indigo-50/40">
                                <td className="px-4 py-3">{(e.date||e.eventDate)||""}{e.time?` • ${e.time}`:""}</td>
                                <td className="px-4 py-3">{e.type||e.eventType}</td>
                                <td className="px-4 py-3">{e.related||e.relatedId||"-"}</td>
                                <td className="px-4 py-3">{e.owner||"-"}</td>
                                <td className="px-4 py-3">{e.status}</td>
                            </tr>
                        ))}
                        {loading && <tr><td className="px-4 py-3" colSpan={5}>Đang tải...</td></tr>}
                        {!loading && rows.length===0 && <tr><td className="px-4 py-3" colSpan={5}>Không có dữ liệu</td></tr>}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
